import 'package:flutter/material.dart';


class MyDeepLinkDelegate extends UriBasedDeepLinkDelegate {
  final _routeNameMap = <String, String>{
    'profile': '/profile',
    'payment' : '/paymentConfirm',
    'defaultRoute' : '/',
  };

  @override
  Map<String, dynamic> buildRequestUrl(Uri uri) => {
    var segments = uri.pathSegments;
    if (segments != null && _routeNameMap[segments[0]] != null){
      return _routeNameMap[segments[0]];
    } else{
      return _routeNameMap['defaultRoute'];
    }
  };
}


void main() {

  final myDeepLinkDelegate = MyDeepLinkDelegate();

  Future<void> runApp(BuildContext context) async {

    // Navigate to a default route.
    await Navigator.of(context).pushNamed('/');

    // Call navigator for pushNamedOrPopNew.
    var navigatorState = Navigator.of(context);
    navigatorState
        .pushNamedOrPopNew('/paymentConfirm', arguments: {'transactionId': 123});
  }
}

